select count(*) from demo_order
where 1=1
and user_id=#{s.userId}
and order_status=#{s.orderStatus}
and logistics_status=#{s.logisticsStatus}
and after_sale_status=#{s.afterSaleStatus}

    and (order_no like concat('%',#{s.keyword},'%') or product_name like concat('%',#{s.keyword},'%'))

select coalesce(sum(order_amount), 0) from demo_order
where 1=1
and user_id=#{s.userId}
and order_status=#{s.orderStatus}
and logistics_status=#{s.logisticsStatus}
and after_sale_status=#{s.afterSaleStatus}

    and (order_no like concat('%',#{s.keyword},'%') or product_name like concat('%',#{s.keyword},'%'))

select * from demo_order
where 1=1
and user_id=#{s.userId}
and order_status=#{s.orderStatus}
and logistics_status=#{s.logisticsStatus}
and after_sale_status=#{s.afterSaleStatus}

    and (order_no like concat('%',#{s.keyword},'%') or product_name like concat('%',#{s.keyword},'%'))

order by updated_at desc, id desc

